   180→// RenderPlannerAssets writes minimal inputs.json and a rendered planner.hcl (with placeholders) into the workspace.
   181→// This is a dry-run helper to prepare artifacts for planner submission later.
   182→func (r *TransflowRunner) RenderPlannerAssets() (*PlannerAssets, error) {
   183→	inputsDir := filepath.Join(r.workspaceDir, "planner", "context")
   184→	outDir := filepath.Join(r.workspaceDir, "planner", "out")
   185→	if err := os.MkdirAll(inputsDir, 0755); err != nil {
   186→		return nil, err
   187→	}
   188→	if err := os.MkdirAll(outDir, 0755); err != nil {
   189→		return nil, err
   190→	}
   191→	// Minimal inputs.json
   192→	inputsPath := filepath.Join(inputsDir, "inputs.json")
   193→	inputs := fmt.Sprintf(`{
   194→  "language": "java",
   195→  "lane": %q,
   196→  "last_error": {"stdout": "", "stderr": ""},
   197→  "deps": {}
   198→}`, r.config.Lane)
   199→
   200→	if err := os.WriteFile(inputsPath, []byte(inputs), 0644); err != nil {
   201→		return nil, err
   202→	}
   203→
   204→	// Copy HCL template
   205→	hclTemplate := filepath.Join("roadmap", "transflow", "jobs", "planner.hcl")
   206→	hclBytes, err := os.ReadFile(hclTemplate)
   207→	if err != nil {
   208→		return nil, fmt.Errorf("failed to read planner.hcl template: %w", err)
   209→	}
   210→
   211→	hclPath := filepath.Join(r.workspaceDir, "planner", "planner.hcl")
   212→	if err := os.WriteFile(hclPath, hclBytes, 0644); err != nil {
   213→		return nil, err
   214→	}
   215→
   216→	return &PlannerAssets{InputsPath: inputsPath, HCLPath: hclPath}, nil
   217→}
