   345→// Run executes the complete transflow workflow
   346→func (r *TransflowRunner) Run(ctx context.Context) (*TransflowResult, error) {
   347→	startTime := time.Now()
   348→	result := &TransflowResult{
   349→		WorkflowID:  r.config.ID,
   350→		StepResults: []StepResult{},
   351→	}
   352→
   353→	// Step 1: Clone repository
   354→	repoPath := filepath.Join(r.workspaceDir, "repo")
   355→	if err := r.gitOps.CloneRepository(ctx, r.config.TargetRepo, r.config.BaseRef, repoPath); err != nil {
   356→		result.ErrorMessage = fmt.Sprintf("failed to clone repository: %v", err)
   357→		result.Duration = time.Since(startTime)
   358→		return nil, fmt.Errorf("failed to clone repository: %w", err)
   359→	}
   360→	result.StepResults = append(result.StepResults, StepResult{
   361→		StepID:  "clone",
   362→		Success: true,
   363→		Message: fmt.Sprintf("Cloned %s at %s", r.config.TargetRepo, r.config.BaseRef),
   364→	})
   365→
   366→	// Step 2: Create and checkout workflow branch
   367→	branchName := GenerateBranchName(r.config.ID)
   368→	result.BranchName = branchName
   369→	if err := r.gitOps.CreateBranchAndCheckout(ctx, repoPath, branchName); err != nil {
   370→		result.ErrorMessage = fmt.Sprintf("failed to create branch: %v", err)
   371→		result.Duration = time.Since(startTime)
   372→		return nil, fmt.Errorf("failed to create branch: %w", err)
   373→	}
   374→	result.StepResults = append(result.StepResults, StepResult{
   375→		StepID:  "create-branch",
   376→		Success: true,
   377→		Message: fmt.Sprintf("Created workflow branch: %s", branchName),
   378→	})
   379→
   380→	// Step 3: Execute recipe steps
   381→	for _, step := range r.config.Steps {
   382→		if step.Type == "recipe" {
   383→			stepStart := time.Now()
   384→			if err := r.recipeExecutor.ExecuteRecipes(ctx, repoPath, step.Recipes); err != nil {
   385→				result.StepResults = append(result.StepResults, StepResult{
   386→					StepID:   step.ID,
   387→					Success:  false,
   388→					Message:  fmt.Sprintf("Recipe execution failed: %v", err),
   389→					Duration: time.Since(stepStart),
   390→				})
   391→				result.ErrorMessage = fmt.Sprintf("failed to execute recipes: %v", err)
   392→				result.Duration = time.Since(startTime)
   393→				return nil, fmt.Errorf("failed to execute recipes: %w", err)
   394→			}
   395→
   396→			result.StepResults = append(result.StepResults, StepResult{
   397→				StepID:   step.ID,
   398→				Success:  true,
   399→				Message:  fmt.Sprintf("Applied recipe: %s", strings.Join(step.Recipes, ", ")),
   400→				Duration: time.Since(stepStart),
   401→			})
   402→		}
   403→	}
   404→
   405→	// Step 4: Commit changes
   406→	commitMessage := fmt.Sprintf("Applied recipe transformations for workflow %s", r.config.ID)
   407→	if err := r.gitOps.CommitChanges(ctx, repoPath, commitMessage); err != nil {
   408→		result.ErrorMessage = fmt.Sprintf("failed to commit changes: %v", err)
   409→		result.Duration = time.Since(startTime)
   410→		return nil, fmt.Errorf("failed to commit changes: %w", err)
   411→	}
   412→	result.StepResults = append(result.StepResults, StepResult{
   413→		StepID:  "commit",
   414→		Success: true,
   415→		Message: "Committed changes",
   416→	})
   417→
   418→	// Step 5: Run build check
   419→	buildStart := time.Now()
   420→	appName := GenerateAppName(r.config.ID)
   421→	timeout, err := r.config.ParseBuildTimeout()
   422→	if err != nil {
   423→		result.ErrorMessage = fmt.Sprintf("invalid build timeout: %v", err)
   424→		result.Duration = time.Since(startTime)
   425→		return nil, fmt.Errorf("invalid build timeout: %w", err)
   426→	}
   427→
   428→	buildConfig := common.DeployConfig{
   429→		App:           appName,
   430→		Lane:          r.config.Lane,
   431→		Environment:   "dev",
   432→		Timeout:       timeout,
   433→		ControllerURL: "", // Will be set by the actual implementation
   434→	}
   435→
   436→	buildResult, err := r.buildChecker.CheckBuild(ctx, buildConfig)
   437→	if err != nil || (buildResult != nil && !buildResult.Success) {
   438→		message := "Build check failed"
   439→		if buildResult != nil && buildResult.Message != "" {
   440→			message = buildResult.Message
   441→		}
   442→		if err != nil {
   443→			message = fmt.Sprintf("%s: %v", message, err)
   444→		}
   445→
   446→		result.StepResults = append(result.StepResults, StepResult{
   447→			StepID:   "build",
   448→			Success:  false,
   449→			Message:  message,
   450→			Duration: time.Since(buildStart),
   451→		})
   452→
   453→		// Check if self-healing is enabled
   454→		if r.config.SelfHeal != nil && r.config.SelfHeal.Enabled && r.jobSubmitter != nil {
   455→			// Attempt healing workflow
   456→			healingSummary, healingErr := r.attemptHealing(ctx, repoPath, message)
   457→			result.HealingSummary = healingSummary
   458→
   459→			if healingErr == nil && healingSummary.Winner != nil {
   460→				// Healing succeeded! Continue with the healed version
   461→				result.StepResults = append(result.StepResults, StepResult{
   462→					StepID:   "healing",
   463→					Success:  true,
   464→					Message:  fmt.Sprintf("Healing succeeded with plan %s", healingSummary.PlanID),
   465→					Duration: time.Since(buildStart),
   466→				})
   467→				// Continue with normal workflow (push, etc.)
   468→			} else {
   469→				// Healing also failed
   470→				result.ErrorMessage = "build check failed and healing failed"
   471→				result.Duration = time.Since(startTime)
   472→				return nil, fmt.Errorf("build check failed: %s (healing also failed: %v)", message, healingErr)
   473→			}
   474→		} else {
   475→			// No healing enabled, fail immediately
   476→			result.ErrorMessage = "build check failed"
   477→			result.Duration = time.Since(startTime)
   478→			return nil, fmt.Errorf("build check failed: %s", message)
   479→		}
   480→	}
   481→
   482→	if buildResult != nil {
   483→		result.BuildVersion = buildResult.Version
   484→	}
   485→	result.StepResults = append(result.StepResults, StepResult{
   486→		StepID:   "build",
   487→		Success:  true,
   488→		Message:  "Build completed successfully",
   489→		Duration: time.Since(buildStart),
   490→	})
   491→
   492→	// Step 6: Push branch
   493→	if err := r.gitOps.PushBranch(ctx, repoPath, r.config.TargetRepo, branchName); err != nil {
   494→		result.StepResults = append(result.StepResults, StepResult{
   495→			StepID:  "push",
   496→			Success: false,
   497→			Message: fmt.Sprintf("Push failed: %v", err),
   498→		})
   499→		result.ErrorMessage = fmt.Sprintf("failed to push branch: %v", err)
   500→		result.Duration = time.Since(startTime)
   501→		return nil, fmt.Errorf("failed to push branch: %w", err)
   502→	}
   503→	result.StepResults = append(result.StepResults, StepResult{
   504→		StepID:  "push",
   505→		Success: true,
   506→		Message: fmt.Sprintf("Pushed branch %s", branchName),
   507→	})
   508→
   509→	// Step 7: Create or update GitLab merge request (if GitProvider is configured)
   510→	if r.gitProvider != nil {
   511→		mrStart := time.Now()
   512→		if err := r.gitProvider.ValidateConfiguration(); err != nil {
   513→			// MR creation is optional - log but don't fail the workflow
   514→			result.StepResults = append(result.StepResults, StepResult{
   515→				StepID:   "mr",
   516→				Success:  false,
   517→				Message:  fmt.Sprintf("MR creation skipped - configuration invalid: %v", err),
   518→				Duration: time.Since(mrStart),
   519→			})
   520→		} else {
   521→			mrConfig := provider.MRConfig{
   522→				RepoURL:      r.config.TargetRepo,
   523→				SourceBranch: branchName,
   524→				TargetBranch: r.config.BaseRef,
   525→				Title:        fmt.Sprintf("Transflow: %s", r.config.ID),
   526→				Description:  r.generateMRDescription(result),
   527→				Labels:       []string{"ploy", "tfl"},
   528→			}
   529→
   530→			mrResult, err := r.gitProvider.CreateOrUpdateMR(ctx, mrConfig)
   531→			if err != nil {
   532→				// MR creation is optional - log but don't fail the workflow
   533→				result.StepResults = append(result.StepResults, StepResult{
   534→					StepID:   "mr",
   535→					Success:  false,
   536→					Message:  fmt.Sprintf("MR creation failed: %v", err),
   537→					Duration: time.Since(mrStart),
   538→				})
   539→			} else {
   540→				action := "created"
   541→				if !mrResult.Created {
   542→					action = "updated"
   543→				}
   544→				result.StepResults = append(result.StepResults, StepResult{
   545→					StepID:   "mr",
   546→					Success:  true,
   547→					Message:  fmt.Sprintf("MR %s: %s", action, mrResult.MRURL),
   548→					Duration: time.Since(mrStart),
   549→				})
   550→				result.MRURL = mrResult.MRURL
   551→			}
   552→		}
   553→	}
   554→
   555→	// Success!
   556→	result.Success = true
   557→	result.Duration = time.Since(startTime)
   558→	return result, nil
   559→}
