   598→// attemptHealing orchestrates the healing workflow: planner → fanout → reducer
   599→func (r *TransflowRunner) attemptHealing(ctx context.Context, repoPath string, buildError string) (*TransflowHealingSummary, error) {
   600→	summary := &TransflowHealingSummary{
   601→		Enabled:       true,
   602→		AttemptsCount: 1,
   603→	}
   604→
   605→	// Step 1: Submit planner job to analyze the build error
   606→	jobHelper := NewJobSubmissionHelper(r.jobSubmitter)
   607→	planResult, err := jobHelper.SubmitPlannerJob(ctx, r.config, buildError, r.workspaceDir)
   608→	if err != nil {
   609→		return summary, fmt.Errorf("planner job failed: %w", err)
   610→	}
   611→
   612→	summary.PlanID = planResult.PlanID
   613→
   614→	// Step 2: Convert planner options to branch specs
   615→	var branches []BranchSpec
   616→	for i, option := range planResult.Options {
   617→		branchID := fmt.Sprintf("option-%d", i)
   618→		if id, ok := option["id"].(string); ok {
   619→			branchID = id
   620→		}
   621→
   622→		branchType := "llm-exec" // default
   623→		if t, ok := option["type"].(string); ok {
   624→			branchType = t
   625→		}
   626→
   627→		branches = append(branches, BranchSpec{
   628→			ID:     branchID,
   629→			Type:   branchType,
   630→			Inputs: option,
   631→		})
   632→	}
   633→
   634→	// Step 3: Execute fanout orchestration
   635→	orchestrator := NewFanoutOrchestrator(r.jobSubmitter)
   636→	maxParallel := 3 // Default parallelism
   637→	if r.config.SelfHeal.MaxRetries > 0 {
   638→		maxParallel = r.config.SelfHeal.MaxRetries
   639→	}
   640→
   641→	winner, allResults, err := orchestrator.RunHealingFanout(ctx, nil, branches, maxParallel)
   642→	summary.AllResults = allResults
   643→
   644→	if err != nil {
   645→		// Fanout failed, but continue to reducer anyway
   646→		summary.Winner = nil
   647→	} else {
   648→		summary.Winner = &winner
   649→	}
   650→
   651→	// Step 4: Submit reducer job to determine next action
   652→	nextAction, reducerErr := jobHelper.SubmitReducerJob(ctx, planResult.PlanID, allResults, summary.Winner, r.workspaceDir)
   653→	if reducerErr != nil {
   654→		return summary, fmt.Errorf("reducer job failed: %w", reducerErr)
   655→	}
   656→
   657→	// If reducer says to stop and we have a winner, healing succeeded
   658→	if nextAction.Action == "stop" && summary.Winner != nil {
   659→		return summary, nil
   660→	}
   661→
   662→	// Otherwise, healing failed
   663→	return summary, fmt.Errorf("healing failed: %s", nextAction.Notes)
   664→}
